log.error("--------------------AfterProvisioning Rule--------------------------"+plan.toXml());

  /*					
  atldapUser Y/N                  =atldapUser  
  ATLDAP-ID (ia)/uniqueUid(la)   =Department
  ATLDAP                         = mail

  log.error("--------------------AfterProvisioning Rule--------------------------"+plan.toXml());

  {
    Link workerDbLink = null;
    Application workerDbAppObj = null;
    List workerDbLinks = null;
    Identity identity = null;
    Link orgLdapLink = null;
    String attReqOp, attReqValue;

    try{
      IdentityService idService = new IdentityService(context);
      Provisioner provisioner = new Provisioner(context);

      if(null != plan){
        identity = plan.getIdentity();
        log.error("======Identity====="+identity);
        List accountRequests = plan.getAccountRequests();
        if(Util.nullSafeSize(accountRequests) > 0){
          for(AccountRequest accReq:accountRequests){
            if("Modify".equals(accReq.getOperation().toString()) && null != accReq.getResult() && accReq.getResult().isCommitted()){
              log.error("===Entered into Modify request  and committed result====");
              workerDbAppObj = context.getObjectByName(Application.class,"ActiveDirectory");

              List orgLdapLinks = idService.getLinks(identity,application);
              if(workerDbAppObj != null){
                workerDbLinks = idService.getLinks(identity,workerDbAppObj);
                if(Util.nullSafeSize(workerDbLinks) > 0 && Util.nullSafeSize(orgLdapLinks) > 0){
                  orgLdapLink = orgLdapLinks.get(0);
                  workerDbLink = workerDbLinks.get(0);
                  log.error(" orgLdapLink    workerDbLink  "+orgLdapLink +"   "+workerDbLink);
                  AttributeRequest attrReq = accReq.getAttributeRequest("atldapUser");
                  log.error(" attrReq  of atldapUser  "+attrReq.toXml());
                  if(null != attrReq) {
                    attReqOp = attrReq.getOperation().toString();
                    attReqValue = attrReq.getValue();
                    if("Add".equals(attReqOp) && "Y".equalsIgnoreCase(attReqValue)){
                      log.error("===Enter Add request====");

                      if(!workerDbLink.isDisabled() && orgLdapLink.isDisabled()){
                        String atldapValue = identity.getStringAttribute("Department") != null?identity.getStringAttribute("Department") : orgLdapLink.getAttribute("Department");
                        if(!atldapValue.equals(workerDbLink.getAttribute("mail"))){
                          ProvisioningPlan workerDbPlan = new ProvisioningPlan();
                          workerDbPlan.setIdentity(identity);
                          AccountRequest workerDbAccReq = new AccountRequest(ProvisioningPlan.AccountRequest.Operation.Modify,workerDbAppObj.getName(),null, null);
                          workerDbAccReq.setNativeIdentity(workerDbLink.getNativeIdentity());
                          workerDbAccReq.add(new AttributeRequest("mail",ProvisioningPlan.Operation.Set,atldapValue));
                          workerDbPlan.add(workerDbAccReq);
                          provisioner.execute(workerDbPlan);
                        }
                      }
                    }
                  }
                  else if(null != attrReq && "Remove".equals(attReqOp) && "Y".equalsIgnoreCase(attReqValue)){
                    log.error("===Entered into remove condition===");
                    String ldapName = plan.getApplicationDisplayName();
                    log.error(" ldapName  ...in else remove op  : "+ldapName);

                    ProvisioningPlan ldapPlan = new ProvisioningPlan();
                    ldapPlan.setIdentity(identity);
                    AccountRequest ldapAccReq = new AccountRequest(ProvisioningPlan.AccountRequest.Operation.Modify,ldapName,null, null);
                    ldapAccReq.setNativeIdentity(workerDbLink.getNativeIdentity());
                    ldapAccReq.add(new AttributeRequest("atldapUser",ProvisioningPlan.Operation.Add,"N"));
                    ldapPlan.add(accReq);
                    provisioner.execute(ldapPlan);
                    log.error("====Added to ldapAccReq succesfully to ldapPlan ==="+ldapPlan.toXml());
                  }
                }
              }
            }
          }
        }
      }
    }
  }

  catch(Exception ex){
    log.error("error in rule : "+ex.toString());
